def test_data_md_lists_data_kinds(project: Path):
    """data.md lists symbols of kind in (class, attribute, variable)."""
    conn = _open_db(project)
    try:
        f_a = _insert_file(conn, "models/user.py")
        _insert_symbol(conn, f_a, "User", "class", line=1)
        _insert_symbol(conn, f_a, "user_email", "attribute", line=5)
        _insert_symbol(conn, f_a, "DEFAULT_ROLE", "variable", line=10)
        # Functions/methods must NOT appear here.
        _insert_symbol(conn, f_a, "save_user", "function", line=20)
        _insert_symbol(conn, f_a, "validate", "method", line=30)
    finally:
        conn.close()

    cmd_render(_args(project))
    body = (_maps_dir(project) / "data.md").read_text(encoding="utf-8")

    assert "User" in body
    assert "user_email" in body
    assert "DEFAULT_ROLE" in body
    assert "save_user" not in body
    assert "validate" not in body


def test_context_with_files_but_no_symbols_renders_placeholder(project: Path):
    """Module that has tracked files but zero parsed symbols still renders cleanly."""
    conn = _open_db(project)
    try:
        # 0 symbols → folds into _module.md rollup (0 < threshold).
        _insert_file(conn, "empty_module/placeholder.py")
    finally:
        conn.close()

    cmd_render(_args(project))
    # 0 symbols is below threshold → rollup page.
    rollup = _context_dir(project) / "empty_module" / "_module.md"
    assert rollup.exists()
    body = rollup.read_text(encoding="utf-8")
    assert "empty_module/placeholder.py" in body
    assert "_No symbols in this module._" in body


def test_api_md_lists_externally_called_functions(project: Path):
    """api.md: functions that are called from OUTSIDE their own file."""
    conn = _open_db(project)
    try:
        f_a = _insert_file(conn, "a.py")
        f_b = _insert_file(conn, "b.py")
        s_public = _insert_symbol(conn, f_a, "public_fn", "function", line=10)
        s_private = _insert_symbol(conn, f_a, "private_fn", "function", line=20)
        s_intra = _insert_symbol(conn, f_a, "intra_caller", "function", line=30)
        s_external = _insert_symbol(conn, f_b, "external_caller", "function", line=40)

        # public_fn called from another file → API
        _insert_edge(conn, s_external, s_public, "calls")
        # private_fn called only by intra_caller in the same file → NOT API
        _insert_edge(conn, s_intra, s_private, "calls")
    finally:
        conn.close()

    cmd_render(_args(project))
    body = (_maps_dir(project) / "api.md").read_text(encoding="utf-8")

    assert "public_fn" in body, "externally-called function must appear in api.md"
    assert "private_fn" not in body, (
        "intra-file callee must NOT appear in api.md (not external)"
    )


