PHASE6_MAP_FILES = {"impact.md", "recent-changes.md", "index.md"}


def test_impact_md_placeholder_when_base_sha_absent(populated_project: Path):
    """Without --base-sha the impact map is a stub, not a BFS report."""
    cmd_render(_args(populated_project))
    body = (_maps_dir(populated_project) / "impact.md").read_text(encoding="utf-8")
    assert "No base SHA provided" in body
    assert "impact map unavailable" in body


def test_impact_md_lists_changed_files_when_base_sha_provided(project: Path):
    """When --base-sha != stored sha, every file is 'changed' and gets a section."""
    conn = _open_db(project)
    try:
        f_a = _insert_file(conn, "pkg_a/changed.py", sha="current")
        _insert_symbol(conn, f_a, "fn_a", "function", line=1)
    finally:
        conn.close()

    cmd_render(_args(project, base_sha="other"))
    body = (_maps_dir(project) / "impact.md").read_text(encoding="utf-8")
    # The changed file appears as a section heading.
    assert "pkg_a/changed.py" in body


def test_impact_md_bfs_walks_two_hops(project: Path):
    """Depth-2 BFS: a→b→c surfaces c as a 2-hop dependent of a."""
    conn = _open_db(project)
    try:
        f_a = _insert_file(conn, "a.py", sha="sa")
        f_b = _insert_file(conn, "b.py", sha="sb")
        f_c = _insert_file(conn, "c.py", sha="sc")
        s_a = _insert_symbol(conn, f_a, "a_fn", "function", line=1)
        s_b = _insert_symbol(conn, f_b, "b_fn", "function", line=1)
        s_c = _insert_symbol(conn, f_c, "c_fn", "function", line=1)
        # a → b → c, so when a changes, both b and c should appear.
        _insert_edge(conn, s_a, s_b, "calls")
        _insert_edge(conn, s_b, s_c, "calls")
    finally:
        conn.close()

    cmd_render(_args(project, base_sha="other"))
    body = (_maps_dir(project) / "impact.md").read_text(encoding="utf-8")
    # Section for the changed file lists both 1-hop and 2-hop dependents.
    # Terminate on the next H2 heading (newline + '## ', not '### ' subheadings).
    a_section = _section(body, "## a.py", "\n## ")
    # b is direct (1-hop), c is transitive (2-hop)
    assert "b.py" in a_section, "1-hop dependent must appear under a.py section"
    assert "c.py" in a_section, "2-hop dependent must appear under a.py section"


def test_impact_md_does_not_walk_three_hops(project: Path):
    """Depth-2 cap: a→b→c→d should NOT surface d under a's section."""
    conn = _open_db(project)
    try:
        f_a = _insert_file(conn, "a.py", sha="sa")
        f_b = _insert_file(conn, "b.py", sha="sb")
        f_c = _insert_file(conn, "c.py", sha="sc")
        f_d = _insert_file(conn, "d.py", sha="sd")
        s_a = _insert_symbol(conn, f_a, "a_fn", "function", line=1)
        s_b = _insert_symbol(conn, f_b, "b_fn", "function", line=1)
        s_c = _insert_symbol(conn, f_c, "c_fn", "function", line=1)
        s_d = _insert_symbol(conn, f_d, "d_fn", "function", line=1)
        _insert_edge(conn, s_a, s_b, "calls")
        _insert_edge(conn, s_b, s_c, "calls")
        _insert_edge(conn, s_c, s_d, "calls")
    finally:
        conn.close()

    cmd_render(_args(project, base_sha="other"))
    body = (_maps_dir(project) / "impact.md").read_text(encoding="utf-8")
    a_section = _section(body, "## a.py", "\n## b.py")
    assert "d.py" not in a_section, "3-hop dependent must NOT appear (depth cap is 2)"


def test_impact_md_walks_any_edge_kind(project: Path):
    """BFS uses any edge kind (calls, imports, inherits)."""
    conn = _open_db(project)
    try:
        f_a = _insert_file(conn, "src.py", sha="ss")
        f_b = _insert_file(conn, "imp_dep.py", sha="sb")
        s_a = _insert_symbol(conn, f_a, "src_fn", "function", line=1)
        s_b = _insert_symbol(conn, f_b, "dep_fn", "function", line=1)
        # Imports edge — must still be walked for impact.
        _insert_edge(conn, s_a, s_b, "imports")
    finally:
        conn.close()

    cmd_render(_args(project, base_sha="other"))
    body = (_maps_dir(project) / "impact.md").read_text(encoding="utf-8")
    src_section = _section(body, "## src.py", "\n## ")
    assert "imp_dep.py" in src_section, (
        "import edges must be walked for impact (any kind, not just calls)"
    )


def test_impact_md_bfs_dedup_visits_once(project: Path):
    """A file reachable at both hop 1 and hop 2 appears at hop 1 only (set semantics)."""
    conn = _open_db(project)
    try:
        f_a = _insert_file(conn, "a.py", sha="sa")
        f_b = _insert_file(conn, "b.py", sha="sb")
        f_c = _insert_file(conn, "c.py", sha="sc")
        s_a = _insert_symbol(conn, f_a, "a_fn", "function", line=1)
        s_b = _insert_symbol(conn, f_b, "b_fn", "function", line=1)
        s_c = _insert_symbol(conn, f_c, "c_fn", "function", line=1)
        # Diamond: a→c (direct), a→b→c (transitive). c must appear once.
        _insert_edge(conn, s_a, s_c, "calls")
        _insert_edge(conn, s_a, s_b, "calls")
        _insert_edge(conn, s_b, s_c, "calls")
    finally:
        conn.close()

    cmd_render(_args(project, base_sha="other"))
    body = (_maps_dir(project) / "impact.md").read_text(encoding="utf-8")
    a_section = _section(body, "## a.py", "\n## b.py")
    # c is reachable at hop 1 directly from a — must not be repeated at hop 2.
    assert a_section.count("- c.py") == 1, (
        "c.py reached at hop 1 must not also list at hop 2 (BFS visited dedup)"
    )


def test_impact_md_empty_edges_no_crash(project: Path):
    """Doom-path: BFS on a DB with no edges → impact.md still renders cleanly."""
    conn = _open_db(project)
    try:
        _insert_file(conn, "lonely.py", sha="sl")
    finally:
        conn.close()

    rc = cmd_render(_args(project, base_sha="other"))
    assert rc == 0
    impact = _maps_dir(project) / "impact.md"
    assert impact.exists()
    body = impact.read_text(encoding="utf-8")
    # Changed file is reported even with no dependents.
    assert "lonely.py" in body


